import { describe, expect, it } from "vitest";
import { parseQuery } from "../src/parseQuery.js";

describe("parseQuery", () => {
  describe("leading question mark", () => {
    it("strips a single leading '?'", () => {
      expect(parseQuery("?a=1")).toEqual({ a: "1" });
    });

    it("parses normally when there is no leading '?'", () => {
      expect(parseQuery("a=1")).toEqual({ a: "1" });
    });

    it("only strips the first character when it is '?'", () => {
      // A second "?" is treated as part of the key.
      expect(parseQuery("??a=1")).toEqual({ "?a": "1" });
    });

    it("returns an empty object for just '?'", () => {
      expect(parseQuery("?")).toEqual({});
    });

    it("does not strip a '?' that is not leading", () => {
      expect(parseQuery("a=1?")).toEqual({ a: "1?" });
    });
  });

  describe("empty input", () => {
    it("returns an empty object for an empty string", () => {
      expect(parseQuery("")).toEqual({});
    });
  });

  describe("pair separation", () => {
    it("separates pairs on '&'", () => {
      expect(parseQuery("a=1&b=2")).toEqual({ a: "1", b: "2" });
    });

    it("skips empty segments from doubled '&'", () => {
      expect(parseQuery("a=1&&b=2")).toEqual({ a: "1", b: "2" });
    });

    it("skips a leading empty segment", () => {
      expect(parseQuery("&a=1")).toEqual({ a: "1" });
    });

    it("skips a trailing empty segment", () => {
      expect(parseQuery("a=1&")).toEqual({ a: "1" });
    });

    it("returns an empty object when all segments are empty", () => {
      expect(parseQuery("&&&")).toEqual({});
    });
  });

  describe("single key", () => {
    it("maps a key that appears once to its string value", () => {
      expect(parseQuery("name=alice")).toEqual({ name: "alice" });
    });

    it("keeps the value as a string, not a number", () => {
      const result = parseQuery("n=42");
      expect(result.n).toBe("42");
      expect(typeof result.n).toBe("string");
    });
  });

  describe("repeated keys", () => {
    it("maps a key that appears twice to an array of values", () => {
      expect(parseQuery("a=1&a=2")).toEqual({ a: ["1", "2"] });
    });

    it("preserves order of appearance", () => {
      expect(parseQuery("a=3&a=1&a=2")).toEqual({ a: ["3", "1", "2"] });
    });

    it("collects three or more occurrences into one array", () => {
      expect(parseQuery("x=a&x=b&x=c&x=d")).toEqual({
        x: ["a", "b", "c", "d"],
      });
    });

    it("handles repeated keys interleaved with other keys", () => {
      expect(parseQuery("a=1&b=x&a=2")).toEqual({ a: ["1", "2"], b: "x" });
    });
  });

  describe("bare keys (no '=')", () => {
    it("maps a bare key to an empty string", () => {
      expect(parseQuery("flag")).toEqual({ flag: "" });
    });

    it("maps a key with '=' but no value to an empty string", () => {
      expect(parseQuery("flag=")).toEqual({ flag: "" });
    });

    it("groups a repeated bare key into an array of empty strings", () => {
      expect(parseQuery("flag&flag")).toEqual({ flag: ["", ""] });
    });

    it("mixes a bare key with valued keys", () => {
      expect(parseQuery("flag&a=1")).toEqual({ flag: "", a: "1" });
    });
  });

  describe("'=' handling within a segment", () => {
    it("splits on the first '=' only, keeping later '=' in the value", () => {
      expect(parseQuery("a=1=2")).toEqual({ a: "1=2" });
    });

    it("allows an empty key before '='", () => {
      expect(parseQuery("=v")).toEqual({ "": "v" });
    });
  });

  describe("'+' decoding", () => {
    it("decodes '+' to a space in values", () => {
      expect(parseQuery("a=hello+world")).toEqual({ a: "hello world" });
    });

    it("decodes '+' to a space in keys", () => {
      expect(parseQuery("first+name=alice")).toEqual({ "first name": "alice" });
    });

    it("decodes multiple '+' characters", () => {
      expect(parseQuery("a=x+y+z")).toEqual({ a: "x y z" });
    });
  });

  describe("percent-decoding", () => {
    it("percent-decodes values", () => {
      expect(parseQuery("a=%20")).toEqual({ a: " " });
    });

    it("percent-decodes keys", () => {
      expect(parseQuery("a%20b=1")).toEqual({ "a b": "1" });
    });

    it("decodes an encoded '&' inside a value", () => {
      expect(parseQuery("a=1%262")).toEqual({ a: "1&2" });
    });

    it("decodes an encoded '=' inside a value", () => {
      expect(parseQuery("a=%3D")).toEqual({ a: "=" });
    });

    it("decodes multi-byte UTF-8 sequences", () => {
      expect(parseQuery("a=%E2%9C%93")).toEqual({ a: "✓" });
    });

    it("applies '+' replacement before percent-decoding", () => {
      // "%20+%20" -> "%20 %20" after '+' replacement -> " " + " " decoded.
      expect(parseQuery("a=%20+%20")).toEqual({ a: "   " });
    });
  });

  describe("invalid percent-encoding never throws", () => {
    it("keeps a lone '%' as-is in a value", () => {
      expect(parseQuery("a=%")).toEqual({ a: "%" });
    });

    it("keeps an incomplete percent sequence as-is", () => {
      expect(parseQuery("a=%zz")).toEqual({ a: "%zz" });
    });

    it("keeps a truncated percent sequence as-is", () => {
      expect(parseQuery("a=%E2%9C")).toEqual({ a: "%E2%9C" });
    });

    it("uses the raw token after '+' replacement when decoding fails", () => {
      // '+' still becomes a space even though percent-decoding fails.
      expect(parseQuery("a=%zz+bad")).toEqual({ a: "%zz bad" });
    });

    it("tolerates invalid encoding in a key", () => {
      expect(parseQuery("%zz=1")).toEqual({ "%zz": "1" });
    });

    it("does not throw for any malformed input", () => {
      expect(() => parseQuery("%&%%&=%&a=%E0%")).not.toThrow();
    });
  });

  describe("combined behavior", () => {
    it("handles a realistic mixed query string", () => {
      expect(
        parseQuery("?q=hello+world&tag=a&tag=b&flag&page=2&raw=%zz"),
      ).toEqual({
        q: "hello world",
        tag: ["a", "b"],
        flag: "",
        page: "2",
        raw: "%zz",
      });
    });
  });
});

